BEGIN
IF AD_isTriggerEnabled()='N' THEN RETURN; END IF;
IF (INSERTING) THEN :NEW.sspr_vac_val_adic := COALESCE(:NEW.additional_day_value, 0) * COALESCE(:NEW.noadditionaltotal, 0); END IF;
IF (UPDATING) THEN -- recalcula solo cuando cambian los campos relevantes IF (:NEW.additional_day_value IS DISTINCT FROM :OLD.additional_day_value) OR (:NEW.noadditionaltotal IS DISTINCT FROM :OLD.noadditionaltotal) THEN :NEW.sspr_vac_val_adic := COALESCE(:NEW.additional_day_value, 0) * COALESCE(:NEW.noadditionaltotal, 0); END IF; END IF;
END SSPR_VACATIONS_VAL_ADIC_TRG
